// Remember Me functionality
function rememberMe(username, passwordHash) {
  const expirationDate = new Date();
  expirationDate.setDate(expirationDate.getDate() + 30);

  document.cookie = `username=${username}; expires=${expirationDate.toUTCString()}; path=/`;
  document.cookie = `passwordHash=${passwordHash}; expires=${expirationDate.toUTCString()}; path=/`;
}

// Auto-login functionality
function autoLogin() {
  const username = document.cookie.split(';').find(cookie => cookie.startsWith('username='))?.split('=')[1];
  const passwordHash = document.cookie.split(';').find(cookie => cookie.startsWith('passwordHash='))?.split('=')[1];

  if (username && passwordHash) {
    // Perform login with the retrieved username and password hash
    // ...
  }
}

// Event listener for checkbox change
const rememberMeCheckbox = document.getElementById('remember-me-checkbox');
rememberMeCheckbox.addEventListener('change', (event) => {
  if (event.target.checked) {
    // Store username and password hash in cookie
    rememberMe(username, passwordHash);
  } else {
    // Clear cookies
    document.cookie = 'username=; expires=Thu, 01 Jan 1970 00:00:01 UTC;';
    document.cookie = 'passwordHash=; expires=Thu, 01 Jan 1970 00:00:01 UTC;';
  }
});

// Call auto-login function on page load
autoLogin();